import base64
import json
from google.cloud import storage
from google.cloud import firestore
from google.cloud import pubsub_v1

def process_gcs_file(event, context):
    client = storage.Client()
    bucket_name = event['bucket']
    file_name = event['name']
    
    bucket = client.get_bucket(bucket_name)
    blob = bucket.blob(file_name)
    file_contents = blob.download_as_text()

    # Process file contents and write to Firestore
    firestore_client = firestore.Client()
    doc_ref = firestore_client.collection("processed_files").document(file_name)
    doc_ref.set({
        'file_name': file_name,
        'content': file_contents
    })

    # Publish message to Pub/Sub
    topic_name = "projects/YOUR_PROJECT_ID/topics/YOUR_TOPIC_NAME"
    publisher = pubsub_v1.PublisherClient()
    topic_path = publisher.topic_path("YOUR_PROJECT_ID", "YOUR_TOPIC_NAME")
    message_json = json.dumps({'file_name': file_name, 'content': file_contents})
    message_bytes = message_json.encode('utf-8')
    
    publisher.publish(topic_path, data=message_bytes)

